    justifyContent: "center",
    fontWeight: 700,
    fontSize: 14,
    flexShrink: 0,
    color: "#fff"
  },
  deptBadge: {
    background: "rgba(139,92,246,0.15)",
    color: "#a78bfa",
    padding: "3px 8px",
    borderRadius: 6,
    fontSize: 11,
    fontWeight: 500
  },
