  },
  modal: {
    background: "#1e293b",
    border: "1px solid rgba(255,255,255,0.1)",
    borderRadius: 20,
    padding: 32,
    textAlign: "center",
    width: 320
  },
  cancelBtn: {
    padding: "10px 24px",
    borderRadius: 10,
    background: "rgba(255,255,255,0.07)",
    border: "1px solid rgba(255,255,255,0.1)",
    color: "#e2e8f0",
